func (s *sqsService) DeleteFromQueue(ctx context.Context, queueUrl string, receiptHandle string) error {
	for i := 0; i < MaxDeleteRetries; i++ {
		_, err := s.sqsClient.DeleteMessage(ctx, &sqs.DeleteMessageInput{
			QueueUrl:      &queueUrl,
			ReceiptHandle: &receiptHandle,
		})
		if err != nil {
			time.Sleep(time.Second * time.Duration(i+1))
		} else {
			return nil
		}
	}

	return fmt.Errorf("[svc.DeleteMessage]: exceeded maximum retry attempts")
}
