func (r *reportConfigurationRepository) BatchDeleteReport(ctx context.Context, reportIds []int64) ([]int64, error) {
	if len(reportIds) == 0 {
		return nil, fmt.Errorf("[BatchDeleteReportConfiguration.BatchDeleteReport] no report IDs provided for deletion")
	}

	r.logger.Info("Start batch deleting reports", zap.Int64s("report_ids", reportIds))

	query, args, err := sqlx.In(scheduleUpdateQuery, reportIds)
	if err != nil {
		return nil, fmt.Errorf("[BatchDeleteReportConfiguration.BatchDeleteReport] failed to construct batch delete query: %w", err)
	}
	query = r.postgresDB.Rebind(query)

	var updatedReportIDs []int64
	err = r.postgresDB.SelectContext(ctx, &updatedReportIDs, query, args...)
	if err != nil {
		return nil, fmt.Errorf("[BatchDeleteReportConfiguration.BatchDeleteReport]: failed to execute batch delete %w", err)
	}
	r.logger.Info("Successfully batch deleted reports", zap.Int64s("deleted_report_ids", updatedReportIDs))
	return updatedReportIDs, nil
}
